const items = $input.all();
const clientes = items.map(i => ({
  cliente_id: i.json.cliente_id,
  total_conversas: i.json.total_conversas,
  score_medio: i.json.score_medio,
  tipos_venda: i.json.tipos_venda,
  resultados: i.json.resultados,
  total_convertidos: i.json.total_convertidos,
  total_perdidos: i.json.total_perdidos,
  dias_desde_ultima: Math.floor((Date.now() - new Date(i.json.ultima_conversa).getTime()) / (1000 * 60 * 60 * 24))
}));
const prompt = `Analise os dados de ${clientes.length} clientes dos últimos 30 dias e identifique de 3 a 5 segmentos comportamentais distintos. Para cada segmento, retorne um JSON array onde cada item tem:\n- nome: nome descritivo do segmento\n- descricao: descrição em até 200 caracteres\n- criterios: objeto com critérios de classificação {score_minimo, score_maximo, frequencia_minima, taxa_conversao_estimada}\n- tamanho_estimado: número estimado de clientes neste segmento\n- perfil_comportamental: objeto com características {recencia, frequencia, valor, engajamento}\n- recomendacao_abordagem: texto com recomendação de abordagem de marketing para este segmento\n\nDados dos clientes:\n${JSON.stringify(clientes.slice(0, 50))}\n\nRetorne APENAS o JSON array de segmentos, sem explicações.`;
return [{
  json: {
    total_clientes: clientes.length,
    prompt
  }
}];

const response = $input.first().json;
const content = response.content?.[0]?.text || '[]';
let parsed;
try {
  parsed = JSON.parse(content);
  if (!Array.isArray(parsed)) parsed = [parsed];
} catch(e) {
  parsed = [{erro: 'parse_failed', raw: content.substring(0,200)}];
}
const results = parsed.map(segmento => ({
  json: {
    ...segmento,
    _raw_response: response
  }
}));
return results.length > 0 ? results : [{json: {erro: 'sem_segmentos'}}];
